-- Local development seed. Runs automatically after migrations on
-- `supabase db reset` (see [db.seed] in config.toml). Never applied to the
-- hosted project — `supabase db push` only ships migrations.
--
-- Creates: the FPL player pool and 10 login accounts. The 7 league teams are
-- already inserted by 20260508000000_initial_schema.sql, so they are not
-- repeated here — teams has no unique key on short_name, so a second insert
-- would silently duplicate them rather than conflict.
--
-- LOGIN CREDENTIALS (local only): every account uses the password
--   localdev
-- Usernames: rohan (admin), auctionmaster (auction_master), guest (guest),
-- team1 ... team7 (team, each linked to the matching club).
--
-- These are throwaway local credentials generated fresh here on purpose —
-- real password hashes are deliberately NOT dumped into the repo. Do not
-- reuse this password anywhere that matters.
--
-- Player rows are public FPL reference data with base_price reset to £1m,
-- i.e. the pre-draft state. Re-run `POST /api/fpl/sync` to refresh them.

-- ─────────────────────────────────────────────
-- USERS (auth.users + auth.identities + public.profiles)
-- ─────────────────────────────────────────────
-- Auth is username + password; the email is a synthetic
-- <username>@surat-fl.internal address the UI never shows.
do $$
declare
  r record;
  v_uid uuid;
  v_team_id uuid;
  v_email text;
begin
  for r in
    select * from (values
      ('rohan',         'admin',          'Rohan',        null),
      ('auctionmaster', 'auction_master', 'Auction Master', null),
      ('guest',         'guest',          'Guest',        null),
      ('team1',         'team',           'Team 1 FC',    'T1'),
      ('team2',         'team',           'Team 2 FC',    'T2'),
      ('team3',         'team',           'Team 3 FC',    'T3'),
      ('team4',         'team',           'Team 4 FC',    'T4'),
      ('team5',         'team',           'Team 5 FC',    'T5'),
      ('team6',         'team',           'Team 6 FC',    'T6'),
      ('team7',         'team',           'Team 7 FC',    'T7')
    ) as t(username, role, display_name, team_short)
  loop
    if exists (select 1 from public.profiles p where p.username = r.username) then
      continue;
    end if;

    v_uid := gen_random_uuid();
    v_email := r.username || '@surat-fl.internal';
    v_team_id := null;
    if r.team_short is not null then
      select id into v_team_id from public.teams where short_name = r.team_short;
    end if;

      instance_id, id, aud, role, email, encrypted_password,
      email_confirmed_at, created_at, updated_at,
      raw_app_meta_data, raw_user_meta_data, is_super_admin,
      confirmation_token, recovery_token, email_change_token_new, email_change
    ) values (
      '00000000-0000-0000-0000-000000000000', v_uid, 'authenticated', 'authenticated',
      v_email, extensions.crypt('localdev', extensions.gen_salt('bf')),
      now(), now(), now(),
      '{"provider":"email","providers":["email"]}'::jsonb, '{}'::jsonb, false,
      '', '', '', ''
    );

      id, user_id, provider_id, identity_data, provider,
      last_sign_in_at, created_at, updated_at
    ) values (
      gen_random_uuid(), v_uid, v_uid::text,
      jsonb_build_object('sub', v_uid::text, 'email', v_email, 'email_verified', true),
      'email', now(), now(), now()
    );

      values (v_uid, r.role, r.username, r.display_name, v_team_id);
  end loop;
end $$;

-- ─────────────────────────────────────────────
-- PLAYERS (FPL reference data, base_price at pre-draft £1m)
-- ─────────────────────────────────────────────

